+export function cellsForWindow(windowWidth, windowHeight, cellWidth, cellHeight, scaleFactor) {
+    const visualWidth = windowWidth * scaleFactor;
+    const visualHeight = windowHeight * scaleFactor;
+    return {
+        cols: Math.max(1, Math.ceil(visualWidth / cellWidth)),
+        rows: Math.max(1, Math.ceil(visualHeight / cellHeight)),
+    };
+}
+
+export class MonitorGrid {
+    constructor(workareaWidth, workareaHeight, cols, rows) {
+        this.cols = cols;
+        this.rows = rows;
+        this.cellWidth = Math.floor(workareaWidth / cols);
+        this.cellHeight = Math.floor(workareaHeight / rows);
+        this._cells = Array.from({length: rows}, () => Array(cols).fill(null));
+        this._windows = new Map();
+    }
+
+    isOccupied(col, row) {
+        if (col < 0 || col >= this.cols || row < 0 || row >= this.rows)
+            return true;
+        return this._cells[row][col] !== null;
+    }
+
+    isAreaFree(col, row, spanCols, spanRows) {
+        for (let r = row; r < row + spanRows; r++) {
+            for (let c = col; c < col + spanCols; c++) {
+                if (this.isOccupied(c, r))
+                    return false;
+            }
+        }
+        return true;
+    }
+
+    _markCells(col, row, spanCols, spanRows, windowId) {
+        for (let r = row; r < row + spanRows; r++) {
+            for (let c = col; c < col + spanCols; c++) {
+                if (r >= 0 && r < this.rows && c >= 0 && c < this.cols)
+                    this._cells[r][c] = windowId;
+            }
+        }
+    }
+
+    placeWindow(windowId, spanCols, spanRows) {
+        for (let r = 0; r <= this.rows - spanRows; r++) {
+            for (let c = 0; c <= this.cols - spanCols; c++) {
+                if (this.isAreaFree(c, r, spanCols, spanRows)) {
+                    this._markCells(c, r, spanCols, spanRows, windowId);
+                    this._windows.set(windowId, {col: c, row: r, spanCols, spanRows});
+                    return {col: c, row: r};
+                }
+            }
+        }
+        return null;
+    }
+
+    placeWindowAt(windowId, col, row, spanCols, spanRows) {
+        if (col + spanCols > this.cols || row + spanRows > this.rows)
+            return false;
+        if (!this.isAreaFree(col, row, spanCols, spanRows))
+            return false;
+        this._markCells(col, row, spanCols, spanRows, windowId);
+        this._windows.set(windowId, {col, row, spanCols, spanRows});
+        return true;
+    }
+
+    removeWindow(windowId) {
+        const info = this._windows.get(windowId);
+        if (!info) return;
+        this._markCells(info.col, info.row, info.spanCols, info.spanRows, null);
+        this._windows.delete(windowId);
+    }
+
+    getWindow(windowId) {
+        return this._windows.get(windowId) || null;
+    }
+
+    cellToPixels(col, row, spanCols, spanRows) {
+        return {
+            x: col * this.cellWidth,
+            y: row * this.cellHeight,
+            width: spanCols * this.cellWidth,
+            height: spanRows * this.cellHeight,
+        };
+    }
+
+    pixelsToCell(x, y) {
+        return {
+            col: Math.min(Math.floor(x / this.cellWidth), this.cols - 1),
+            row: Math.min(Math.floor(y / this.cellHeight), this.rows - 1),
+        };
+    }
+
+    get windowCount() { return this._windows.size; }
+    getAllWindows() { return new Map(this._windows); }
+}

