+#!/usr/bin/env -S gjs -m
+import { describe, it, assertEqual, assertDeepEqual, assertTrue, assertFalse, assertNull, printResults } from './run.js';
+import { MonitorGrid, cellsForWindow } from '../lib/gridEngine.js';
+
+describe('cellsForWindow', () => {
+    it('calculates cell occupancy at 100% scale', () => {
+        const result = cellsForWindow(720, 540, 240, 180, 1.0);
+        assertEqual(result.cols, 3);
+        assertEqual(result.rows, 3);
+    });
+    it('calculates cell occupancy at 50% scale', () => {
+        const result = cellsForWindow(720, 540, 240, 180, 0.5);
+        assertEqual(result.cols, 2);
+        assertEqual(result.rows, 2);
+    });
+    it('calculates cell occupancy at 25% scale', () => {
+        const result = cellsForWindow(720, 540, 240, 180, 0.25);
+        assertEqual(result.cols, 1);
+        assertEqual(result.rows, 1);
+    });
+    it('minimum occupancy is 1x1', () => {
+        const result = cellsForWindow(100, 100, 240, 180, 0.25);
+        assertEqual(result.cols, 1);
+        assertEqual(result.rows, 1);
+    });
+});
+
+describe('MonitorGrid', () => {
+    it('creates grid with correct cell dimensions', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        assertEqual(grid.cellWidth, 240);
+        assertEqual(grid.cellHeight, 180);
+    });
+    it('places a window via best-fit into empty grid', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const pos = grid.placeWindow('win1', 3, 3);
+        assertEqual(pos.col, 0);
+        assertEqual(pos.row, 0);
+        assertTrue(grid.isOccupied(0, 0));
+        assertTrue(grid.isOccupied(2, 2));
+    });
+    it('places second window next to first', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        grid.placeWindow('win1', 3, 3);
+        const pos = grid.placeWindow('win2', 3, 3);
+        assertEqual(pos.col, 3);
+        assertEqual(pos.row, 0);
+    });
+    it('removes window and frees cells', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        grid.placeWindow('win1', 3, 3);
+        grid.removeWindow('win1');
+        assertFalse(grid.isOccupied(0, 0));
+    });
+    it('places window at specific position', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const ok = grid.placeWindowAt('win1', 4, 2, 3, 3);
+        assertTrue(ok);
+        assertTrue(grid.isOccupied(4, 2));
+        assertTrue(grid.isOccupied(6, 4));
+    });
+    it('rejects placement at occupied position', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        grid.placeWindow('win1', 4, 4);
+        const ok = grid.placeWindowAt('win2', 2, 2, 3, 3);
+        assertFalse(ok);
+    });
+    it('checks if position is available', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        assertTrue(grid.isAreaFree(0, 0, 3, 3));
+        grid.placeWindow('win1', 3, 3);
+        assertFalse(grid.isAreaFree(0, 0, 3, 3));
+        assertTrue(grid.isAreaFree(3, 0, 3, 3));
+    });
+    it('returns pixel rect for cell position', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const rect = grid.cellToPixels(2, 1, 3, 2);
+        assertEqual(rect.x, 480);
+        assertEqual(rect.y, 180);
+        assertEqual(rect.width, 720);
+        assertEqual(rect.height, 360);
+    });
+    it('returns cell position for pixel coordinates', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const cell = grid.pixelsToCell(500, 200);
+        assertEqual(cell.col, 2);
+        assertEqual(cell.row, 1);
+    });
+});
+
+import System from 'system';
+const allPassed = printResults();
+if (!allPassed) System.exit(1);
